-- spool_bom 테이블 생성 및 데이터 등록 (material 스키마)
-- SQL Editor에서 실행하세요

CREATE TABLE IF NOT EXISTS material.spool_bom (
    id bigserial primary key,
    system text,
    iso_dwg_no text,
    line_no text,
    description text,
    tag_no text,
    size text,
    uom text default 'EA',
    qty numeric default 1
);

GRANT SELECT ON material.spool_bom TO anon;

TRUNCATE TABLE material.spool_bom;

